{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyNKx3XbLOp8VYOvohhj6q6X"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"5873rLJn585a","executionInfo":{"status":"ok","timestamp":1777477376311,"user_tz":-330,"elapsed":19,"user":{"displayName":"Nandana S","userId":"09011285804801661207"}},"outputId":"361e9fb0-d49f-4d3d-b8a0-a812898abee3"},"outputs":[{"output_type":"stream","name":"stdout","text":["Set after adding elements: {1, 2, 3, 4, 5}\n","\n","After removing 3: {1, 2, 4, 5}\n","After discarding 10 (not present): {1, 2, 4, 5}\n","\n","Original set after modification: {1, 2, 4, 5, 6}\n","Copied set: {1, 2, 4, 5}\n","\n","After clear(): set()\n","\n","Check if 2 exists: True\n","\n","Union: {1, 2, 3, 4, 5, 6}\n","Intersection: {3, 4}\n","Difference (set1 - set2): {1, 2}\n","Symmetric Difference: {1, 2, 5, 6}\n","After update set1: {1, 2, 3, 4, 5, 6}\n"]}],"source":["# -------------------------------\n","# BASIC LEVEL\n","# -------------------------------\n","\n","# 1. Create empty set and add 5 elements\n","s = set()\n","s.add(1)\n","s.add(2)\n","s.add(3)\n","s.add(4)\n","s.add(5)\n","print(\"Set after adding elements:\", s)\n","\n","# 2. Remove element using remove() and discard()\n","s.remove(3)   # removes 3\n","print(\"\\nAfter removing 3:\", s)\n","\n","s.discard(10)  # no error even if element not present\n","print(\"After discarding 10 (not present):\", s)\n","\n","# 3. Copy set and modify original\n","s_copy = s.copy()\n","s.add(6)\n","print(\"\\nOriginal set after modification:\", s)\n","print(\"Copied set:\", s_copy)\n","\n","# 4. Clear set\n","temp_set = {10, 20, 30}\n","temp_set.clear()\n","print(\"\\nAfter clear():\", temp_set)\n","\n","# 5. Check element exists\n","print(\"\\nCheck if 2 exists:\", 2 in s)\n","\n","\n","# -------------------------------\n","# INTERMEDIATE LEVEL\n","# -------------------------------\n","\n","set1 = {1, 2, 3, 4}\n","set2 = {3, 4, 5, 6}\n","\n","# 6. Union\n","print(\"\\nUnion:\", set1.union(set2))\n","\n","# 7. Intersection\n","print(\"Intersection:\", set1.intersection(set2))\n","\n","# 8. Difference\n","print(\"Difference (set1 - set2):\", set1.difference(set2))\n","\n","# 9. Symmetric Difference\n","print(\"Symmetric Difference:\", set1.symmetric_difference(set2))\n","\n","# 10. Update\n","set1.update(set2)\n","print(\"After update set1:\", set1)"]}]}